	var qualityRunner agent.AgentRunner
	if f.AgentRunnerOverride != nil {
		qualityRunner = f.AgentRunnerOverride
	}
	lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
	intakeLog := cmd.OutOrStdout()
	if dispatch.JSON == "true" {
		intakeLog = io.Discard
	}
	innerIntakeHook := agent.NewPreClaimIntakeHookWithLogVerbose(projectRoot, store, rcfg, nil, qualityRunner, intakeLog, f.viperInstance.GetBool("verbose"))
	intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
	triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
	proseHook := f.proseEvidenceHookOverride
	if proseHook == nil {

	} else {
		fmt.Println("⚠️  Meta-Prompt Out of Sync")
		if verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "meta_prompt_sync",
				Description: metaPromptCheck.Error(),
				Remediation: []string{
					"Run 'ddx update' to sync meta-prompt",
				},
				SystemInfo: map[string]string{
					"claude_file": filepath.Join(f.WorkingDir, "CLAUDE.md"),
				},
			})
		}
	}

	// Check 10: Installed Package Launchers
	checkInstalledLaunchers(verbose)

	if auditPlugins {
		pluginIssues := checkInstalledPlugins(verbose)
		if len(pluginIssues) > 0 {
			allGood = false
			issues = append(issues, pluginIssues...)
		}
	}

	// Check 11: Sync failure marker — surfaces aborted 'ddx sync' runs.
	fmt.Print("✓ Checking Sync Status... ")
	syncFailurePath := filepath.Join(f.WorkingDir, ".ddx", "sync-failure.json")
	if ws := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); ws != "" {
		syncFailurePath = filepath.Join(ws, ".ddx", "sync-failure.json")
	}
	if syncIssue := checkSyncFailure(syncFailurePath); syncIssue != nil {
		fmt.Println("⚠️  Sync aborted")
		fmt.Printf("   ⚠️  %s\n", syncIssue.Description)
		for _, r := range syncIssue.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *syncIssue)
	} else {
		fmt.Println("✅ Sync Status")
	}

	// Check 12: package.json locations — detect missing/stale node_modules.
	fmt.Print("✓ Checking package.json locations... ")
	pkgIssues := checkPackageJSONLocations(f.WorkingDir)
	if len(pkgIssues) == 0 {
		fmt.Println("✅ Node dependencies up to date")
	} else {
		fmt.Printf("⚠️  %d location(s) need 'bun install'\n", len(pkgIssues))
		for _, issue := range pkgIssues {
			fmt.Printf("   ⚠️  %s\n", issue.Description)
			for _, r := range issue.Remediation {
				fmt.Printf("   💡 %s\n", r)
			}
		}
		issues = append(issues, pkgIssues...)
	}

	// Check 13: Legacy symlinks under project skill directories (FEAT-015).
	// In the project-local model all skills are real files. Symlinks indicate
	// a pre-migration install; ddx update --force replaces them.
	if legacyDirs := legacySkillSymlinkDirs(f.WorkingDir); len(legacyDirs) > 0 {
		errOut := cmd.ErrOrStderr()
		for _, dir := range legacyDirs {
			fmt.Fprintf(errOut, "symlink detected under %s; pre-migration install detected\n", dir)
		}
		fmt.Fprintln(errOut, "run: ddx update --force")
		return fmt.Errorf("legacy skill symlinks detected")
	}

	fmt.Println()
	if allGood && len(issues) == 0 {
		fmt.Println("🎉 All critical checks passed! DDX is ready to use.")
	} else if allGood && len(issues) > 0 {
		fmt.Println("⚠️  Some non-critical issues detected. DDX is functional but may have limitations.")
		fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
	} else {
		fmt.Println("⚠️  Some issues detected. DDX may have limited functionality.")
		fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
	}

	// Generate detailed diagnostic report if verbose or issues detected
	if verbose || len(issues) > 0 {
		generateDiagnosticReport(issues, verbose, f.WorkingDir)
	}

	return nil
}

// legacySkillSymlinkDirs returns the relative names of skill directories
// (e.g. ".agents/skills", ".claude/skills") under workingDir that contain
// at least one symlink. A symlink indicates a pre-FEAT-015 install.
func legacySkillSymlinkDirs(workingDir string) []string {
	if workingDir == "" {
		return nil
	}
	var found []string
	for _, rel := range []string{".agents/skills", ".claude/skills"} {
		dir := filepath.Join(workingDir, rel)
		entries, err := os.ReadDir(dir)
		if err != nil {
			continue
		}
		for _, e := range entries {
			info, err := e.Info()
			if err != nil {
				continue
			}
			if info.Mode()&os.ModeSymlink != 0 {
				found = append(found, rel)
				break
			}
		}
	}
	return found
}

// runDoctorScoped runs only the checks relevant to the staged file paths,
// skipping global installation health checks unrelated to those files.
// It is the entry point when the ddx-validate pre-commit hook passes --paths.
//
// Scope rules:
//   - path == ".ddx.yml" (or ends with "/.ddx.yml") → config category: run config validation
//   - path under templates/, patterns/, prompts/ → resource category: validate resource files
//
// Any other paths (e.g. Go source files staged alongside config) are silently
// ignored — the scoped run only validates the DDx-relevant categories present
// in the staged set. Global checks (legacy symlinks, binary location, git repo
// health, etc.) are never run in scoped mode.
func (f *CommandFactory) runDoctorScoped(paths []string) error {
	cats := categorizeStagedPaths(paths)
	if cats["config"] {
		if !checkConfiguration() {
			return fmt.Errorf("DDx configuration invalid; run 'ddx doctor' for details")
		}
	}
	// Resource category: syntax/schema checks for templates, patterns, prompts.
	// Currently no additional validation beyond categorisation; the hook gate
	// is satisfied by a clean parse (no-op until resource validators are added).
	_ = cats["resource"]
	return nil
}

// categorizeStagedPaths maps each path to a DDx check category.
// Returns a set of category names ("config", "resource") that apply to the
// given path list. Unrecognised paths produce no category.
func categorizeStagedPaths(paths []string) map[string]bool {
	cats := make(map[string]bool)
	resourcePrefixes := []string{"templates/", "patterns/", "prompts/"}
	for _, p := range paths {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		if p == ".ddx.yml" || strings.HasSuffix(p, "/.ddx.yml") || filepath.Base(p) == ".ddx.yml" {
			cats["config"] = true
		}
		for _, prefix := range resourcePrefixes {
			if strings.HasPrefix(p, prefix) || strings.Contains(p, "/"+prefix) {
				cats["resource"] = true
			}
		}
	}
	return cats
}

// checkBinaryInstallLocation verifies the running binary is at the canonical install
// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
// SHA-256 differs from the running binary.
func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
	var issues []DiagnosticIssue

	homeDir, err := os.UserHomeDir()
	if err != nil {
		return issues
	}

	canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")

	// (2) Check whether running binary matches the canonical install location.
	resolvedExec, _ := filepath.EvalSymlinks(executable)
	if resolvedExec == "" {
		resolvedExec = executable
	}
	resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
	execMatchesCanonical := resolvedExec == canonicalPath ||
		(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
	if !execMatchesCanonical {
		issues = append(issues, DiagnosticIssue{
			Type:        "binary_not_canonical",
			Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
			Remediation: []string{
				"Re-run install.sh to reinstall to the canonical location",
				fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
			},
		})
	}

	// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
	runningSHA, err := computeFileSHA256(executable)
	if err != nil {
		return issues
	}

	seen := make(map[string]bool)
	for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
		candidate := filepath.Join(dir, "ddx")
		if seen[candidate] {
			continue
		}
		seen[candidate] = true

		info, err := os.Stat(candidate)
		if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
			continue
		}

		candidateSHA, err := computeFileSHA256(candidate)
		if err != nil {
			continue
		}

		if candidateSHA == runningSHA {
			continue // same binary, not stale
		}

		issues = append(issues, DiagnosticIssue{
			Type:        "binary_sha_mismatch",
			Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
			Remediation: []string{
				fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
				"Or re-run install.sh to update all copies",
			},
		})
	}

	return issues
}

// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
func computeFileSHA256(path string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f.Close()

	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return "", err
	}
	return hex.EncodeToString(h.Sum(nil)), nil
}

// isInPath checks if DDX is accessible from PATH
func isInPath() bool {
	_, err := exec.LookPath("ddx")
	return err == nil
}

// Package workerstatus reports on live "ddx work" / "ddx try" processes,
// scoped to a specific project root by default.
//
// Operators and agents asking "is the worker still working beads?" must be
// able to answer the question for one project at a time. A global process
// scan ("ps aux | grep ddx work") returns workers from every checkout on the
// machine and produces a misleading "yes, working" signal when the worker
// belongs to a different repository. This package filters live workers by
// the resolved project root so the answer always matches the question.
package workerstatus

import (
	"context"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// LiveWorker describes one running ddx worker process.
type LiveWorker struct {
	PID               int       `json:"pid"`
	Command           string    `json:"command"`
	StartedAt         time.Time `json:"started_at"`
	AgeSeconds        float64   `json:"age_seconds"`
	Age               string    `json:"age"`
	ProjectRoot       string    `json:"project_root"`
	BeadID            string    `json:"bead_id,omitempty"`
	ExecutionWorktree string    `json:"execution_worktree,omitempty"`
	Cwd               string    `json:"cwd,omitempty"`
}

// Scanner discovers live ddx worker processes on the host.
type Scanner interface {
	Scan(ctx context.Context) ([]LiveWorker, error)
}

// New returns the platform-appropriate Scanner. On Linux this reads /proc.
// On other platforms it returns an empty list; the caller's tests and the
// --all-projects escape hatch remain meaningful regardless.
func New() Scanner {
	return newSystemScanner()
}

// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
// total) embedded in argv strings or worktree paths.
var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)

// executionWorktreePattern matches the conventional execute-bead worktree
// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
// in a path. The directory name is enough to identify the worktree even when
// the surrounding path is unconventional.
var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)

// InferBead extracts a bead ID and execution worktree path from the worker's
// command line and current working directory. It returns the longest worktree
// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
// the inline worker has chdir'd into the isolated worktree), and the first
// bead ID matched in either the command line or the worktree path.
//
// Either return value may be empty when no signal is present, which is the
// expected case for a long-running `ddx work` drain that has not yet started
// a specific bead.
func InferBead(cmdline, cwd string) (beadID, worktree string) {
	worktree = extractWorktreePath(cwd)
	if worktree == "" {
		worktree = extractWorktreePath(cmdline)
	}

	if m := beadIDPattern.FindString(worktree); m != "" {
		beadID = m
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cmdline); m != "" {
			beadID = m
		}
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cwd); m != "" {
			beadID = m
		}
	}
	return beadID, worktree
}

func extractWorktreePath(s string) string {
	if s == "" {
		return ""
	}
	if !strings.Contains(s, ".execute-bead-wt-") {
		return ""
	}
	matches := executionWorktreePattern.FindStringIndex(s)
	if matches == nil {
		return ""
	}
	end := matches[1]
	for end < len(s) {
		r := s[end]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		end++
	}
	return s[:end]
}

// FilterByProject returns workers whose ProjectRoot resolves to the same path
// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
// filepath.EvalSymlinks so a symlinked checkout matches its real path.
func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
	target := canonicalPath(projectRoot)
	out := make([]LiveWorker, 0, len(workers))
	for _, w := range workers {
		if SamePath(w.ProjectRoot, target) {
			out = append(out, w)
		}
	}
	return out
}

// SamePath reports whether a and b refer to the same on-disk location after
// canonicalisation. It tolerates empty inputs (returning false) so callers
// can safely compare optional fields without prefiltering.
func SamePath(a, b string) bool {
	ca := canonicalPath(a)
	cb := canonicalPath(b)
	if ca == "" || cb == "" {
		return false
	}
	return ca == cb
}

func canonicalPath(p string) string {
	if strings.TrimSpace(p) == "" {
		return ""
	}
	abs, err := filepath.Abs(p)
	if err != nil {
		abs = filepath.Clean(p)
	}
	if resolved, err := filepath.EvalSymlinks(abs); err == nil {
		return resolved
	}
	return abs
}

// FormatAge renders a duration as a short human-readable string mirroring
// the conventions used by the server-backed worker list (`5s`, `12m`,
// `1h30m`). It is intended for terminal output; JSON output uses
// AgeSeconds as the numeric source of truth.
func FormatAge(d time.Duration) string {
	if d < time.Minute {
		if d < 0 {
			d = 0
		}
		return roundedSeconds(d)
	}
	if d < time.Hour {
		return roundedMinutes(d)
	}
	hours := int(d.Hours())
	mins := int(d.Minutes()) % 60
	if mins == 0 {
		return durationHours(hours)
	}
	return durationHoursMinutes(hours, mins)
}

func roundedSeconds(d time.Duration) string {
	secs := int(d.Seconds())
	return durationSeconds(secs)
}

func roundedMinutes(d time.Duration) string {
	mins := int(d.Minutes())
	return durationMinutes(mins)
}

func durationSeconds(n int) string { return formatUnit(n, "s") }
func durationMinutes(n int) string { return formatUnit(n, "m") }
func durationHours(n int) string   { return formatUnit(n, "h") }
func durationHoursMinutes(h, m int) string {
	return formatUnit(h, "h") + formatUnit(m, "m")
}

func formatUnit(n int, unit string) string {
	if n < 0 {
		n = 0
	}
	return itoa(n) + unit
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	var digits [20]byte
	i := len(digits)
	for n > 0 {
		i--
		digits[i] = byte('0' + n%10)
		n /= 10
	}
	out := string(digits[i:])
	if neg {
		return "-" + out
	}
	return out
}

package workerstatus

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"time"
)

// LivenessRecord is the worker-side sidecar written under
// .ddx/workers/<worker-id>/status.json to mirror live progress of a
// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
//
// The bead tracker remains the durable claim marker; this sidecar carries
// the high-frequency liveness signal so operators can answer "is the worker
// alive and what is it doing?" without inflating tracker churn.
type LivenessRecord struct {
	WorkerID       string    `json:"worker_id"`
	ProjectRoot    string    `json:"project_root,omitempty"`
	CurrentBead    string    `json:"current_bead,omitempty"`
	AttemptID      string    `json:"attempt_id,omitempty"`
	Phase          string    `json:"phase,omitempty"`
	Route          string    `json:"route,omitempty"`
	Harness        string    `json:"harness,omitempty"`
	Model          string    `json:"model,omitempty"`
	Profile        string    `json:"profile,omitempty"`
	PID            int       `json:"pid,omitempty"`
	ChildPID       int       `json:"child_pid,omitempty"`
	StartedAt      time.Time `json:"started_at,omitempty"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// LivenessTTL is the freshness window for treating a worker sidecar as
// "active". Defaults to 3× the bead tracker heartbeat interval (which is
// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
var LivenessTTL = 90 * time.Second

// LivenessDir returns the worker sidecar directory for a project.
func LivenessDir(projectRoot string) string {
	return filepath.Join(projectRoot, ".ddx", "workers")
}

// LivenessPath returns the status.json path for a worker under projectRoot.
func LivenessPath(projectRoot, workerID string) string {
	return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
}

// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
// tmp-then-rename so concurrent readers never see a half-written file.
func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
	if projectRoot == "" || workerID == "" {
		return fmt.Errorf("workerstatus: project root and worker id required")
	}
	dir := filepath.Join(LivenessDir(projectRoot), workerID)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
	}
	data, err := json.MarshalIndent(rec, "", "  ")
	if err != nil {
		return fmt.Errorf("workerstatus: marshal liveness: %w", err)
	}
	data = append(data, '\n')
	final := filepath.Join(dir, "status.json")
	tmp, err := os.CreateTemp(dir, "status-*.tmp")
	if err != nil {
		return fmt.Errorf("workerstatus: create tmp: %w", err)
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: write tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: close tmp: %w", err)
	}
	if err := os.Rename(tmpName, final); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: rename: %w", err)
	}
	return nil
}

// ReadLiveness reads the sidecar for workerID under projectRoot.
func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
	var rec LivenessRecord
	data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
	if err != nil {
		return rec, err
	}
	if err := json.Unmarshal(data, &rec); err != nil {
		return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
	}
	return rec, nil
}

// ListLiveness reads every status.json sidecar under projectRoot's worker
// directory. Malformed sidecars are skipped silently — the sidecar is
// best-effort observability, not authoritative state.
func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
	dir := LivenessDir(projectRoot)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var out []LivenessRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := ReadLiveness(projectRoot, entry.Name())
		if err != nil {
			continue
		}
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		return out[i].LastActivityAt.After(out[j].LastActivityAt)
	})
	return out, nil
}

// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
func (r LivenessRecord) IsFresh(now time.Time) bool {
	if r.LastActivityAt.IsZero() {
		return false
	}
	return now.Sub(r.LastActivityAt) <= LivenessTTL
}

package work

import (
	"encoding/json"
	"io"
	"os"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

// LivenessReporter observes worker liveness ticks. WithHeartbeat invokes
// OnTick after each TouchClaimHeartbeat so the caller can mirror the same
// signal to a worker-status sidecar and to the optional server probe
// without rewriting the bead tracker.
type LivenessReporter interface {
	OnTick(now time.Time)
}

// SidecarLivenessReporter is the production LivenessReporter. Each tick it
// (a) writes a status.json sidecar under .ddx/workers/<worker-id>/ via the
// workerstatus package, and (b) emits a worker.heartbeat envelope to sink
// (typically the loop EventSink, which is teed to the workerprobe). The
// sidecar write is best-effort and never fails the loop; the sink emit is
// best-effort and never blocks the heartbeat goroutine.
type SidecarLivenessReporter struct {
	mu          sync.Mutex
	projectRoot string
	rec         workerstatus.LivenessRecord
	sink        io.Writer
	sessionID   string
}

// NewSidecarLivenessReporter constructs a SidecarLivenessReporter for the
// given worker. projectRoot must be the project's git root (where .ddx/
// lives). sink may be nil for callers that don't want event mirroring.
func NewSidecarLivenessReporter(projectRoot, workerID, sessionID string, sink io.Writer) *SidecarLivenessReporter {
	return &SidecarLivenessReporter{
		projectRoot: projectRoot,
		sink:        sink,
		sessionID:   sessionID,
		rec: workerstatus.LivenessRecord{
			WorkerID:    workerID,
			ProjectRoot: projectRoot,
			PID:         os.Getpid(),
			StartedAt:   time.Now().UTC(),
		},
	}
}

// SetAttempt records the in-flight attempt identity. Called once per claim
// before WithHeartbeat starts so the first tick records the right bead.
func (r *SidecarLivenessReporter) SetAttempt(beadID, attemptID, phase, route, harness, model, profile string, childPID int) {
	if r == nil {
		return
	}
	r.mu.Lock()
	r.rec.CurrentBead = beadID
	r.rec.AttemptID = attemptID
	r.rec.Phase = phase
	r.rec.Route = route
	r.rec.Harness = harness
	r.rec.Model = model
	r.rec.Profile = profile
	r.rec.ChildPID = childPID
	r.mu.Unlock()
}

// ClearAttempt drops the in-flight attempt identity once the attempt
// terminates. The worker_id and project_root remain so an idle drain loop
// still presents as the same worker between attempts.
func (r *SidecarLivenessReporter) ClearAttempt() {
	if r == nil {
		return
	}
	r.mu.Lock()
	r.rec.CurrentBead = ""
	r.rec.AttemptID = ""
	r.rec.Phase = ""
	r.rec.ChildPID = 0
	r.mu.Unlock()
}

// OnTick updates the sidecar with the new last_activity_at and mirrors a
// worker.heartbeat envelope to the configured sink (best-effort).
func (r *SidecarLivenessReporter) OnTick(now time.Time) {
	if r == nil {
		return
	}
	r.mu.Lock()
	r.rec.LastActivityAt = now.UTC()
	snapshot := r.rec
	r.mu.Unlock()
	_ = workerstatus.WriteLiveness(r.projectRoot, snapshot.WorkerID, snapshot)
	r.emit(snapshot, now)
}

// Snapshot returns a copy of the current sidecar record.
func (r *SidecarLivenessReporter) Snapshot() workerstatus.LivenessRecord {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.rec
}

func (r *SidecarLivenessReporter) emit(rec workerstatus.LivenessRecord, now time.Time) {
	if r.sink == nil {
		return
	}
	entry := map[string]any{
		"session_id": r.sessionID,
		"type":       "worker.heartbeat",
		"ts":         now.UTC().Format(time.RFC3339Nano),
		"data": map[string]any{
			"worker_id":        rec.WorkerID,
			"bead_id":          rec.CurrentBead,
			"attempt_id":       rec.AttemptID,
			"phase":            rec.Phase,
			"route":            rec.Route,
			"harness":          rec.Harness,
			"model":            rec.Model,
			"profile":          rec.Profile,
			"last_activity_at": rec.LastActivityAt.Format(time.RFC3339Nano),
		},
	}
	line, err := json.Marshal(entry)
	if err != nil {
		return
	}
	line = append(line, '\n')
	_, _ = r.sink.Write(line)
}

package cmd

import (
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/spf13/cobra"
)

type cleanupCommandReport struct {
	DryRun                      bool                                `json:"dry_run"`
	ProjectRoot                 string                              `json:"project_root"`
	TempRoot                    string                              `json:"temp_root"`
	ScannedTempDirs             int                                 `json:"scanned_temp_dirs"`
	ScannedEvidenceDirs         int                                 `json:"scanned_evidence_dirs"`
	CompleteEvidenceDirs        int                                 `json:"complete_evidence_dirs"`
	ScannedScratchDirs          int                                 `json:"scanned_scratch_dirs"`
	RemovedUnregisteredTempDirs int64                               `json:"removed_unregistered_temp_dirs"`
	RemovedRegisteredWorktrees  int64                               `json:"removed_registered_worktrees"`
	RemovedRunStateFiles        int64                               `json:"removed_run_state_files"`
	RemovedScratchDirs          int64                               `json:"removed_scratch_dirs"`
	PreservedActiveScratchDirs  int64                               `json:"preserved_active_scratch_dirs"`
	BytesReclaimed              int64                               `json:"bytes_reclaimed"`
	InodesReclaimed             int64                               `json:"inodes_reclaimed"`
	ScratchBytesReclaimed       int64                               `json:"scratch_bytes_reclaimed"`
	ScratchInodesReclaimed      int64                               `json:"scratch_inodes_reclaimed"`
	Warnings                    []agent.ExecutionCleanupWarning     `json:"warnings"`
	BlockedErrors               []agent.ExecutionCleanupIssue       `json:"blocked_errors"`
	Observations                []agent.ExecutionCleanupObservation `json:"observations"`
}

func (f *CommandFactory) newCleanupCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "cleanup",
		Short: "Inspect and clean stale DDx execution resources",
		Long: `Inspect DDx-owned execution resources and conservatively clean stale state.

By default, cleanup runs in dry-run mode and reports what it would remove.
Use --apply to remove stale DDx temp worktrees, stale run-state files, and
other DDx-owned scratch resources under the configured project roots.

Examples:
  ddx cleanup
  ddx cleanup --json
  ddx cleanup --apply
  ddx cleanup --project /path/to/project --apply`,
		Args: cobra.NoArgs,
		RunE: f.runCleanup,
	}

	cmd.Flags().Bool("apply", false, "Actually remove stale DDx execution resources")
	cmd.Flags().Bool("json", false, "Output the cleanup report as JSON")
	cmd.Flags().String("project", "", "Project root to inspect (default: detected from CWD)")
	return cmd
}

func (f *CommandFactory) runCleanup(cmd *cobra.Command, args []string) error {
	_ = args
	projectFlag, _ := cmd.Flags().GetString("project")
	apply, _ := cmd.Flags().GetBool("apply")
	asJSON, _ := cmd.Flags().GetBool("json")

	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	if projectRoot == "" {
		projectRoot = f.WorkingDir
	}

	mgr := agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{})
	mgr.DryRun = !apply

	summary, err := mgr.Cleanup(cmd.Context())
	if err != nil {
		return err
	}

	report := cleanupCommandReport{
		DryRun:                      !apply,
		ProjectRoot:                 summary.ProjectRoot,
		TempRoot:                    summary.TempRoot,
		ScannedTempDirs:             summary.ScannedTempDirs,
		ScannedEvidenceDirs:         summary.ScannedEvidenceDirs,
		CompleteEvidenceDirs:        summary.CompleteEvidenceDirs,
		ScannedScratchDirs:          summary.ScannedScratchDirs,
		RemovedUnregisteredTempDirs: summary.RemovedUnregisteredTempDirs,
		RemovedRegisteredWorktrees:  summary.RemovedRegisteredWorktrees,
		RemovedRunStateFiles:        summary.RemovedRunStateFiles,
		RemovedScratchDirs:          summary.RemovedScratchDirs,
		PreservedActiveScratchDirs:  summary.PreservedActiveScratchDirs,
		BytesReclaimed:              summary.BytesReclaimed,
		InodesReclaimed:             summary.InodesReclaimed,
		ScratchBytesReclaimed:       summary.ScratchBytesReclaimed,
		ScratchInodesReclaimed:      summary.ScratchInodesReclaimed,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), summary.Warnings...),
		Observations:                append([]agent.ExecutionCleanupObservation(nil), summary.Observations...),
	}
	for _, issue := range summary.Issues {
		if issue.Blocking {
			report.BlockedErrors = append(report.BlockedErrors, issue)
		}
	}
	if report.Warnings == nil {
		report.Warnings = []agent.ExecutionCleanupWarning{}
	}
	if report.BlockedErrors == nil {
		report.BlockedErrors = []agent.ExecutionCleanupIssue{}
	}
	if report.Observations == nil {
		report.Observations = []agent.ExecutionCleanupObservation{}
	}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(report)
	}

	out := cmd.OutOrStdout()
	verb := "removed"
	if report.DryRun {
		verb = "would remove"
	}
	fmt.Fprintf(out, "cleanup: %s %d stale temp dir(s), %d registered worktree(s), %d run-state file(s), %d scratch dir(s)\n",
		verb,
		report.RemovedUnregisteredTempDirs,
		report.RemovedRegisteredWorktrees,
		report.RemovedRunStateFiles,
		report.RemovedScratchDirs,
	)
	if report.BytesReclaimed > 0 || report.InodesReclaimed > 0 {
		fmt.Fprintf(out, "cleanup: %s %d byte(s), %d inode(s)\n", verb, report.BytesReclaimed, report.InodesReclaimed)
	}
	if report.ScratchBytesReclaimed > 0 || report.ScratchInodesReclaimed > 0 || report.PreservedActiveScratchDirs > 0 {
		fmt.Fprintf(out, "cleanup: scratch scope %s %d byte(s), %d inode(s); preserved %d active scratch dir(s)\n",
			verb,
			report.ScratchBytesReclaimed,
			report.ScratchInodesReclaimed,
			report.PreservedActiveScratchDirs,
		)
	}
	if report.CompleteEvidenceDirs > 0 {
		fmt.Fprintf(out, "cleanup: preserved %d complete evidence bundle(s)\n", report.CompleteEvidenceDirs)
	}
	for _, warning := range report.Warnings {
		fmt.Fprintf(out, "warning: %s (%s): %s\n", warning.Path, warning.Class, warning.Message)
	}
	for _, issue := range report.BlockedErrors {
		fmt.Fprintf(out, "blocked: %s (%s): %s\n", issue.Path, issue.Class, issue.Message)
	}
	if report.DryRun {
		fmt.Fprintln(out, "run again with --apply to remove these resources")
	}
	return nil
}

