func (s *cleanupAdvanceAwareStore) ReadyExecution() ([]bead.Bead, error) {
	ready := atomic.AddInt32(s.readyCalls, 1)
	if ready == 1 {
		atomic.StoreInt32(&s.firstReadyCleanupCount, atomic.LoadInt32(s.cleanupCalls))
